import { create } from 'zustand'

const useTreeStore = create((set) => ({
    treeData: [],
    setTreeData: (data) => set((state) => ({
        treeData: [...state.treeData, ...data.map((item) => {
            return {
                ...item,
                isExpanded: false
            }
        })]
    }))
}))

export default useTreeStore
